.ds-btn-primary {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 28px;
  background: #3B8E8C;
  color: #FFFFFF;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 1.125rem;
  font-weight: 600;
  line-height: 1.25;
  border: none;
  border-radius: 9999px;
  cursor: pointer;
  transition: background 200ms cubic-bezier(0.16, 1, 0.3, 1), transform 200ms cubic-bezier(0.16, 1, 0.3, 1);
  box-shadow: inset 0 1px 0 0 rgba(255,255,255,0.15);
}
.ds-btn-primary:hover {
  background: #2E7371;
  transform: translateY(-1px);
}
.ds-btn-primary:active {
  transform: translateY(0);
  background: #2A6B69;
}
.ds-btn-primary:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(59,142,140,0.3), 0 0 20px rgba(59,142,140,0.15), inset 0 1px 0 0 rgba(255,255,255,0.15);
}
.ds-btn-arrow {
  display: inline-block;
  transition: transform 300ms cubic-bezier(0.16, 1, 0.3, 1);
}
.ds-btn-primary:hover .ds-btn-arrow {
  transform: translateX(3px);
}
@media (prefers-reduced-motion: reduce) {
  .ds-btn-primary,
  .ds-btn-arrow {
    transition: none !important;
  }
  .ds-btn-primary:hover {
    transform: none !important;
  }
  .ds-btn-primary:hover .ds-btn-arrow {
    transform: none !important;
  }
}

.ds-btn-ghost {
  display: inline-flex;
  align-items: center;
  padding: 10px 22px;
  background: transparent;
  color: #2C2826;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 1.125rem;
  font-weight: 600;
  line-height: 1.25;
  border: 1.5px solid rgba(44,40,38,0.10);
  border-radius: 12px;
  cursor: pointer;
  transition: background 200ms cubic-bezier(0.16, 1, 0.3, 1), border-color 200ms cubic-bezier(0.16, 1, 0.3, 1);
}
.ds-btn-ghost:hover {
  background: rgba(44,40,38,0.06);
  border-color: rgba(44,40,38,0.18);
}
.ds-btn-ghost:active {
  background: rgba(44,40,38,0.10);
}
.ds-btn-ghost:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(59,142,140,0.3);
  border-color: #3B8E8C;
}
@media (prefers-reduced-motion: reduce) {
  .ds-btn-ghost { transition: none !important; }
}

.ds-btn-cta {
  display: inline-flex;
  align-items: center;
  padding: 12px 32px;
  background: #D4973A;
  color: #2C2826;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 1.125rem;
  font-weight: 600;
  line-height: 1.25;
  border: none;
  border-radius: 9999px;
  cursor: pointer;
  transition: background 200ms cubic-bezier(0.16, 1, 0.3, 1), transform 200ms cubic-bezier(0.16, 1, 0.3, 1);
  box-shadow: inset 0 1px 0 0 rgba(255,255,255,0.25);
}
.ds-btn-cta:hover {
  background: #C88B30;
  transform: translateY(-1px);
}
.ds-btn-cta:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(212,151,58,0.3), 0 0 20px rgba(212,151,58,0.2), inset 0 1px 0 0 rgba(255,255,255,0.25);
}
@media (prefers-reduced-motion: reduce) {
  .ds-btn-cta { transition: none !important; }
  .ds-btn-cta:hover { transform: none !important; }
}

.ds-input-wrapper {
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.ds-input-label {
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 0.75rem;
  font-weight: 500;
  line-height: 1;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: #7A7069;
}
.ds-input {
  padding: 10px 14px;
  background: #FFFFFF;
  color: #2C2826;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 0.9375rem;
  line-height: 1.6;
  border: 1.5px solid rgba(44,40,38,0.10);
  border-radius: 10px;
  outline: none;
  transition: border-color 200ms cubic-bezier(0.16, 1, 0.3, 1), box-shadow 200ms cubic-bezier(0.16, 1, 0.3, 1);
}
.ds-input::placeholder {
  color: #7A7069;
  opacity: 1;
}
.ds-input:focus {
  border-color: #3B8E8C;
  box-shadow: 0 0 0 2px rgba(59,142,140,0.3), 0 0 20px rgba(59,142,140,0.15);
}
.ds-input:disabled {
  background: rgba(44,40,38,0.04);
  color: #7A7069;
  cursor: not-allowed;
}
@media (prefers-reduced-motion: reduce) {
  .ds-input { transition: none !important; }
}

.ds-cmdbar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 6px 6px 18px;
  background: #FFFFFF;
  border: 1.5px solid rgba(44,40,38,0.10);
  border-radius: 14px;
  transition: border-color 200ms cubic-bezier(0.16, 1, 0.3, 1), box-shadow 200ms cubic-bezier(0.16, 1, 0.3, 1);
  box-shadow: 0 2px 8px rgba(44,40,38,0.04);
}
.ds-cmdbar:focus-within {
  border-color: #3B8E8C;
  box-shadow: 0 0 0 2px rgba(59,142,140,0.15), 0 4px 16px rgba(44,40,38,0.06);
}
.ds-cmdbar-input {
  flex: 1;
  padding: 8px 0;
  background: transparent;
  color: #2C2826;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 1rem;
  font-weight: 500;
  border: none;
  outline: none;
}
.ds-cmdbar-input::placeholder {
  color: #7A7069;
  opacity: 1;
}
.ds-cmdbar-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 18px;
  background: #3B8E8C;
  color: #FFFFFF;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 0.9375rem;
  font-weight: 600;
  border: none;
  border-radius: 9999px;
  cursor: pointer;
  transition: background 200ms cubic-bezier(0.16, 1, 0.3, 1);
  box-shadow: inset 0 1px 0 0 rgba(255,255,255,0.15);
}
.ds-cmdbar-btn:hover {
  background: #2E7371;
}
.ds-cmdbar-btn:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(59,142,140,0.3);
}
@media (prefers-reduced-motion: reduce) {
  .ds-cmdbar,
  .ds-cmdbar-input,
  .ds-cmdbar-btn { transition: none !important; }
}

.ds-card {
  padding: 24px;
  background: #EFE8DE;
  border-radius: 12px;
  transition: box-shadow 200ms cubic-bezier(0.16, 1, 0.3, 1), transform 200ms cubic-bezier(0.16, 1, 0.3, 1);
}
.ds-card:hover {
  box-shadow: 0 4px 16px rgba(44,40,38,0.08), 0 1px 3px rgba(44,40,38,0.06);
  transform: translateY(-2px);
}
.ds-card-title {
  margin: 0 0 8px 0;
  font-family: 'Nunito', system-ui, sans-serif;
  font-size: 1.125rem;
  font-weight: 600;
  line-height: 1.25;
  color: #2C2826;
}
.ds-card-body {
  margin: 0;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 0.9375rem;
  line-height: 1.6;
  color: #7A7069;
}
@media (prefers-reduced-motion: reduce) {
  .ds-card { transition: none !important; }
  .ds-card:hover { transform: none !important; }
}

.ds-nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 56px;
  padding: 0 24px;
  background: #EFE8DE;
  border-bottom: 1px solid rgba(44,40,38,0.10);
}
.ds-nav-brand {
  display: flex;
  align-items: center;
  gap: 10px;
}
.ds-nav-icon {
  width: 34px;
  height: 34px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(155deg, #C96A4D, #B05439);
  color: #FFFFFF;
  font-family: 'Nunito', system-ui, sans-serif;
  font-size: 16px;
  font-weight: 700;
  border-radius: 10px;
}
.ds-nav-wordmark {
  display: flex;
  flex-direction: column;
  line-height: 0.9;
}
.ds-nav-name {
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 1.25rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  text-transform: uppercase;
  color: #2C2826;
}
.ds-nav-tag {
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 9px;
  font-weight: 500;
  letter-spacing: 0.34em;
  text-transform: uppercase;
  color: #7A7069;
}
.ds-nav-actions {
  display: flex;
  gap: 4px;
}
.ds-nav-action {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  border: none;
  border-radius: 10px;
  cursor: pointer;
  transition: background 200ms cubic-bezier(0.16, 1, 0.3, 1);
}
.ds-nav-action:hover {
  background: rgba(44,40,38,0.08);
}
.ds-nav-action:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(59,142,140,0.3);
}
@media (prefers-reduced-motion: reduce) {
  .ds-nav-action { transition: none !important; }
}

.ds-marquee {
  overflow: hidden;
  border-top: 1px solid rgba(44,40,38,0.10);
  border-bottom: 1px solid rgba(44,40,38,0.10);
  background: rgba(239,232,222,0.3);
  backdrop-filter: blur(8px);
}
.ds-marquee-track {
  display: inline-flex;
  white-space: nowrap;
  animation: ds-marquee-scroll 30s linear infinite;
}
.ds-marquee-item {
  display: inline-flex;
  align-items: center;
  padding: 10px 20px;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: #7A7069;
}
.ds-marquee-sep {
  display: inline-flex;
  align-items: center;
  color: #3B8E8C;
  font-size: 10px;
}
@keyframes ds-marquee-scroll {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}
@media (prefers-reduced-motion: reduce) {
  .ds-marquee-track { animation: none !important; }
}

.ds-modal {
  background: #EFE8DE;
  border-radius: 12px;
  box-shadow: 0 8px 32px rgba(44,40,38,0.12), 0 2px 8px rgba(44,40,38,0.08);
  overflow: hidden;
}
.ds-modal-header {
  padding: 24px 24px 0;
}
.ds-modal-title {
  margin: 0;
  font-family: 'Nunito', system-ui, sans-serif;
  font-size: 1.5rem;
  font-weight: 600;
  line-height: 1.15;
  color: #2C2826;
}
.ds-modal-body {
  padding: 16px 24px 24px;
}
.ds-modal-desc {
  margin: 0;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 0.9375rem;
  line-height: 1.6;
  color: #7A7069;
}
.ds-modal-footer {
  display: flex;
  justify-content: flex-end;
  gap: 12px;
  padding: 16px 24px;
  border-top: 1px solid rgba(44,40,38,0.10);
}
